class LazyPageProxy(QWidget):
    """
    Hafif proxy widget - gercek sayfayi ilk gosterildiginde olusturur.
    Stack'e eklenir ama icerik sadece ensure_loaded() cagrildiginda yaratilir.
    """

    def __init__(self, page_id: str, page_class, theme: dict):
        super().__init__()
        self.page_id = page_id
        self._page_class = page_class
        self._theme = theme
        self._real_page = None
        self._loaded = False

        # Skeleton placeholder
        self._layout = QVBoxLayout(self)
        self._layout.setContentsMargins(0, 0, 0, 0)
        self._skeleton = SkeletonCardLoader()
        bg = theme.get('bg_hover', theme.get('bg_card', '#1E1E1E'))
        shimmer = theme.get('border', theme.get('border_light', '#2A2A2A'))
        self._skeleton.set_theme_colors(bg, shimmer)
        self._layout.addWidget(self._skeleton)

    @property
    def loaded(self) -> bool:
        return self._loaded

    @property
    def real_page(self):
        return self._real_page

    def ensure_loaded(self) -> QWidget:
        """Gercek sayfayi olustur (henuz olusturulmadiysa)"""
        if self._loaded:
            return self._real_page
        try:
            self._real_page = self._page_class(self._theme)
            if self._skeleton:
                self._skeleton.stop()
                self._skeleton.setParent(None)
                self._skeleton.deleteLater()
                self._skeleton = None
            self._layout.addWidget(self._real_page)
            self._loaded = True
            logger.info("Sayfa yuklendi: %s", self.page_id)
        except Exception as e:
            logger.error("Sayfa yuklenemedi (%s): %s", self.page_id, e)
            raise
        return self._real_page

    def update_stored_theme(self, theme: dict):
        """Tema degistiginde sayfayi yeniden olusturmak uzere isaretler.

        Sayfalar inline setStyleSheet() ile olusturuldugundan,
        tema degisikligi ancak sayfayi yeniden olusturarak uygulanabilir.
        """
        self._theme = theme
        if self._loaded and self._real_page:
            # Sayfayi yok et ve lazy-load'a geri dondur
            self._real_page.setParent(None)
            self._real_page.deleteLater()
            self._real_page = None
            self._loaded = False
            self._pending_recreate = True
            logger.info("Sayfa tema icin yeniden olusturulacak: %s", self.page_id)
        elif self._skeleton:
            bg = theme.get('bg_hover', theme.get('bg_card', '#1E1E1E'))
            shimmer = theme.get('border', theme.get('border_light', '#2A2A2A'))
            self._skeleton.set_theme_colors(bg, shimmer)

    def _ensure_skeleton(self):
        """Skeleton placeholder'i geri yukle (sayfa yeniden olusturulacaksa)"""
        if self._skeleton is None:
            self._skeleton = SkeletonCardLoader()
            bg = self._theme.get('bg_hover', self._theme.get('bg_card', '#1E1E1E'))
            shimmer = self._theme.get('border', self._theme.get('border_light', '#2A2A2A'))
            self._skeleton.set_theme_colors(bg, shimmer)
            self._layout.addWidget(self._skeleton)

