def parse_arguments():
    """Komut satırı argümanlarını parse et"""
    parser = argparse.ArgumentParser(
        description='NEXOR ERP - Kurumsal Kaynak Planlama Sistemi',
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Örnekler:
  python main.py              Normal başlatma
  python main.py --setup      Veritabanı ayarları ile başlat
  python main.py --reset-db   DB ayarlarını sıfırla
        """
    )
    parser.add_argument(
        '--setup', '-s',
        action='store_true',
        help='Veritabanı ayar wizard\'ını aç'
    )
    parser.add_argument(
        '--reset-db',
        action='store_true',
        help='Veritabanı ayarlarını sıfırla ve wizard aç'
    )
    parser.add_argument(
        '--version', '-v',
        action='version',
        version=f'NEXOR ERP {VERSION}'
    )
    return parser.parse_args()


def check_database_connection() -> tuple[bool, str]:
    """
    Veritabanı bağlantısını kontrol et
    Returns: (başarılı, hata_mesajı)
    """
    try:
        from core.external_config import config_manager
        
        # Config dosyası var mı?
        if config_manager.needs_setup():
            return False, "Veritabanı ayarları yapılmamış"
        
        # Bağlantı testi
        success, message = config_manager.test_connection()
        return success, message
        
    except ImportError:
        # external_config yoksa config.py'den dene
        try:
            from core.database import get_db_connection
            conn = get_db_connection()
            if conn:
                conn.close()
                return True, "OK"
            return False, "Bağlantı kurulamadı"
        except Exception as e:
            return False, str(e)
    except Exception as e:
        return False, str(e)


def show_setup_wizard(app: QApplication, force: bool = False) -> bool:
    """
    Setup wizard'ı göster
    Returns: True = devam et, False = çıkış
    """
    try:
        from dialogs.setup_wizard import SetupWizard
        
        wizard = SetupWizard()
        result = wizard.exec()
        
        if result == QDialog.Accepted:
            logger.info("Veritabanı ayarları kaydedildi")
            # Config'i yeniden yükle
            try:
                from core.external_config import config_manager
                config_manager.reload()
            except:
                pass
            return True
        else:
            if force:
                # Zorunlu kurulum, iptal edilemez
                QMessageBox.warning(
                    None,
                    "Kurulum Gerekli",
                    "Veritabanı ayarları yapılmadan uygulama çalışamaz.\n"
                    "Lütfen ayarları yapın veya uygulamayı kapatın."
                )
                return show_setup_wizard(app, force=True)
            return False
            
    except Exception as e:
        logger.error("Setup wizard hatası: %s", e)
        QMessageBox.critical(
            None,
            "Hata",
            f"Setup wizard açılamadı:\n{e}"
        )
        return False


class ErrorDialog(QDialog):
    """Hata mesajı dialog"""
    
    def __init__(self, error_title: str, error_message: str, parent=None):
        super().__init__(parent)
        self.setWindowTitle(f"HATA: {error_title}")
        self.setMinimumSize(800, 600)
        self.setWindowFlags(self.windowFlags() | Qt.WindowStaysOnTopHint)
        
        layout = QVBoxLayout(self)
        
        # Hata mesajı
        error_text = QTextEdit()
        error_text.setReadOnly(True)
        error_text.setPlainText(error_message)
        error_text.setStyleSheet("""
            QTextEdit {
                background: #1e1e1e;
                color: #ff6b6b;
                font-family: 'Courier New', monospace;
                font-size: 11px;
                padding: 10px;
            }
        """)
        layout.addWidget(error_text)
        
        # Butonlar
        btn_layout = QHBoxLayout()
        
        copy_btn = QPushButton("Kopyala")
        copy_btn.clicked.connect(lambda: QApplication.clipboard().setText(error_message))
        btn_layout.addWidget(copy_btn)
        
        btn_layout.addStretch()
        
        close_btn = QPushButton("Kapat")
        close_btn.clicked.connect(self.accept)
        btn_layout.addWidget(close_btn)
        
        layout.addLayout(btn_layout)


