    def _create_pages(self):
        """Tüm sayfaları lazy proxy olarak oluştur"""
        # Sistem Ayarları özel (signal bağlantısı gerekiyor) - hemen yükle
        try:
            self.settings_page = SistemAyarPage(
                self.theme,
                self.current_mode,
                self.current_color,
                self.expanded_mode,
                self.logo_path
            )
            self.settings_page.settings_changed.connect(self._on_settings_changed)
            self.pages["sistem_ayar"] = self.settings_page
            self.stack.addWidget(self.settings_page)
        except Exception as e:
            logger.warning("Sistem Ayarları sayfası oluşturulamadı: %s", e)

        # Diğer sayfalar - lazy proxy ile
        for page_id, page_class in PAGE_CLASSES.items():
            if page_id != "sistem_ayar":
                try:
                    proxy = LazyPageProxy(page_id, page_class, self.theme)
                    self.pages[page_id] = proxy
                    self.stack.addWidget(proxy)
                except Exception as e:
                    logger.warning("Sayfa proxy oluşturma hatası (%s): %s", page_id, e)
    
    def _on_menu_clicked(self, menu_id: str):
        """Menü tıklandığında"""
        try:
            self._show_page(menu_id)
        except Exception as e:
            logger.error("Sayfa gösterilemedi (%s): %s", menu_id, e)
            QMessageBox.warning(self, "Hata", f"Sayfa açılamadı: {menu_id}\n\n{str(e)}")
    
    def _show_page(self, page_id: str):
        """Sayfayı göster (lazy load + fade animasyonu)"""
        if page_id not in self.pages:
            return

        try:
            widget = self.pages[page_id]

            # LazyPageProxy ise gercek sayfayi olustur
            if isinstance(widget, LazyPageProxy):
                widget.ensure_loaded()

            # Fade animasyonlu gecis
            self._animated_switch(widget)

            self.header.set_title(get_page_title(page_id))

            # Sayfa refresh metodu varsa çağır
            real = widget.real_page if isinstance(widget, LazyPageProxy) else widget
            if real and hasattr(real, 'on_page_shown'):
                real.on_page_shown()
        except Exception as e:
            logger.error("Sayfa gösterilemedi: %s", e)
            raise

    def _animated_switch(self, target_widget: QWidget):
        """Fade-out → switch → fade-in gecisi"""
        current = self.stack.currentWidget()

        if current is None or current is target_widget:
            self.stack.setCurrentWidget(target_widget)
            return

        # Fade-out mevcut sayfa
        effect = QGraphicsOpacityEffect(current)
        current.setGraphicsEffect(effect)

        fade_out = QPropertyAnimation(effect, b"opacity")
        fade_out.setDuration(120)
        fade_out.setStartValue(1.0)
        fade_out.setEndValue(0.0)
        fade_out.setEasingCurve(QEasingCurve.OutQuad)

        def on_fade_out_done():
            current.setGraphicsEffect(None)
            self.stack.setCurrentWidget(target_widget)

            # Fade-in yeni sayfa
            effect_in = QGraphicsOpacityEffect(target_widget)
            target_widget.setGraphicsEffect(effect_in)

            fade_in = QPropertyAnimation(effect_in, b"opacity")
            fade_in.setDuration(120)
            fade_in.setStartValue(0.0)
            fade_in.setEndValue(1.0)
            fade_in.setEasingCurve(QEasingCurve.InQuad)
            fade_in.finished.connect(lambda: target_widget.setGraphicsEffect(None))
            fade_in.start()
            # prevent GC
            target_widget._fade_anim = fade_in

        fade_out.finished.connect(on_fade_out_done)
        fade_out.start()
        # prevent GC
        current._fade_anim = fade_out
    
    def _toggle_theme(self):
        """Sidebar'daki tema butonuna basıldığında - Dark/Light değiştir"""
        try:
            # Modu değiştir
            new_mode = "light" if self.current_mode == "dark" else "dark"
            self.current_mode = new_mode

            # Temayı yeniden oluştur
            self.theme = build_theme(self.current_mode, self.current_color)

            # Tüm bileşenleri güncelle
            self._apply_theme()

            # Sidebar
            self.sidebar.set_dark_mode(self.current_mode == "dark")
            self.sidebar.update_theme(self.theme)

            # Header
            self.header.update_theme(self.theme)

            # Sayfaların temasını güncelle (yeniden oluşturmadan)
            self._update_page_themes()

            # Sistem ayarları sayfasını da güncelle
            if hasattr(self, 'settings_page'):
                self.settings_page.current_mode = self.current_mode
                if hasattr(self.settings_page, 'mode_combo'):
                    index = 0 if self.current_mode == "dark" else 1
                    self.settings_page.mode_combo.setCurrentIndex(index)

            # Ayarları kaydet
            self._save_settings()
        except Exception as e:
            logger.error("Tema değiştirilemedi: %s", e)
            QMessageBox.critical(self, "Tema Hatası", f"Tema değiştirilemedi:\n\n{str(e)}")
    
    def _update_page_themes(self):
        """Tema degistiginde tum sayfalari guncelle.

        LazyPageProxy sayfalarini yeniden olusturmak uzere isaretler.
        Aktif gorunen sayfayi hemen yeniden olusturur.
        """
        try:
            current_widget = self.stack.currentWidget() if hasattr(self, 'stack') else None

            for page_id, widget in self.pages.items():
                if isinstance(widget, LazyPageProxy):
                    widget.update_stored_theme(self.theme)
                    # Aktif gorunen sayfa ise hemen yeniden olustur
                    if widget is current_widget and not widget.loaded:
                        widget.ensure_loaded()
                elif page_id == "sistem_ayar":
                    # Sistem ayarları sayfası özel - kendi update_theme'i var
                    if hasattr(widget, 'update_theme'):
                        widget.update_theme(self.theme)
                else:
                    # Doğrudan yüklenmiş widget
                    if hasattr(widget, 'update_theme'):
                        widget.update_theme(self.theme)
                    elif hasattr(widget, '_apply_global_style'):
                        widget.theme = self.theme
                        widget._apply_global_style()
        except Exception as e:
            logger.error("Sayfa temaları güncellenemedi: %s", e)
            raise
    
    def _on_settings_changed(self, mode: str, color: str, expanded: bool, logo: str):
        """Ayarlar değiştiğinde (Sistem Ayarları sayfasından)"""
        try:
            needs_restart = (expanded != self.expanded_mode)
            
            self.current_mode = mode
            self.current_color = color
            self.expanded_mode = expanded
            self.logo_path = logo if logo else None
            
            self.theme = build_theme(mode, color)
            self._apply_theme()
            
            # Sidebar güncelle
            self.sidebar.set_dark_mode(mode == "dark")
            self.sidebar.update_theme(self.theme)
            self.sidebar.set_logo(self.logo_path)
            
            # Header güncelle
            self.header.update_theme(self.theme)
            
            # Sayfaların temasını güncelle (yeniden oluşturmadan)
            self._update_page_themes()

            self._save_settings()

            if needs_restart:
                QMessageBox.information(
                    self,
                    "Menü Stili",
                    "Menü stili değişikliği için uygulamayı yeniden başlatın."
                )
        except Exception as e:
            logger.error("Ayarlar uygulanamadı: %s", e)
            QMessageBox.critical(self, "Ayar Hatası", f"Ayarlar uygulanamadı:\n\n{str(e)}")
    
    def _toggle_sidebar(self):
        """Sidebar'ı gizle/göster"""
        try:
            if self.sidebar.isVisible():
                self.sidebar.hide()
            else:
                self.sidebar.show()
        except Exception as e:
            logger.error("Sidebar toggle hatası: %s", e)
    
    def closeEvent(self, event):
        """Pencere kapanırken"""
        # PDKS servisini durdur
        if PDKS_SERVICE_AVAILABLE:
            try:
                stop_pdks_service()
                logger.info("PDKS Reader Service durduruldu")
            except Exception as e:
                logger.warning("PDKS servisi durdurulurken hata: %s", e)

        # PLC Sync servisini durdur
        if PLC_SYNC_AVAILABLE:
            try:
                stop_plc_sync_service()
                logger.info("PLC Sync Service durduruldu")
            except Exception as e:
                logger.warning("PLC Sync servisi durdurulurken hata: %s", e)

        event.accept()


